SELECT model_id
FROM model_evaluations
WHERE accuracy = (
  SELECT MAX(accuracy)
  FROM model_evaluations
);

SELECT AVG(accuracy) AS average_accuracy
FROM model_evaluations
WHERE model_id = (SELECT model_id FROM model_uploads WHERE upload_id = 1);

SELECT model_id
FROM model_uploads
WHERE user_id IN (SELECT user_id FROM users WHERE role = 'data scientist');
